+export interface Graph {
+  nodes: string[];
+  edges: Array<{ from: string; to: string; weight?: number }>;
+  adjacency: Map<string, Map<string, number>>;
+}
+
+export interface Partition {
+  groups: string[][];
+  cutWeight: number;
+  modularity: number;
