+        low.set(node, Math.min(low.get(node)!, discovery.get(neighbor)!));
+      }
+    }
+  }
+
+  for (const node of graph.nodes) {
+    if (!visited.has(node)) {
+      parent.set(node, null);
+      dfs(node);
+    }
+  }
+
+  return bridges;
+}
