+}
+
+// Helper functions
+function normalize(v: Float64Array) {
+  let sum = 0;
+  for (let i = 0; i < v.length; i++) {
+    sum += v[i] * v[i];
+  }
+  const norm = Math.sqrt(sum);
+  if (norm > 0) {
+    for (let i = 0; i < v.length; i++) {
+      v[i] /= norm;
+    }
+  }
+}
