+function dotProduct(a: Float64Array, b: Float64Array): number {
+  let sum = 0;
+  for (let i = 0; i < a.length; i++) {
+    sum += a[i] * b[i];
+  }
+  return sum;
+}
+
+function kMeans(points: number[][], k: number, maxIter: number = 100): number[] {
+  const n = points.length;
+  if (n === 0 || k === 0) return [];
+
+  const dim = points[0].length;
+
+  // Random initialization
+  const centroids: number[][] = [];
+  const used = new Set<number>();
+  while (centroids.length < Math.min(k, n)) {
+    const idx = Math.floor(Math.random() * n);
+    if (!used.has(idx)) {
+      used.add(idx);
+      centroids.push([...points[idx]]);
+    }
+  }
+
+  const assignment = new Array(n).fill(0);
+
+  for (let iter = 0; iter < maxIter; iter++) {
+    // Assign points to nearest centroid
+    let changed = false;
+    for (let i = 0; i < n; i++) {
+      let minDist = Infinity;
+      let minC = 0;
+      for (let c = 0; c < centroids.length; c++) {
+        let dist = 0;
+        for (let d = 0; d < dim; d++) {
+          dist += Math.pow(points[i][d] - centroids[c][d], 2);
+        }
+        if (dist < minDist) {
+          minDist = dist;
+          minC = c;
+        }
+      }
+      if (assignment[i] !== minC) {
+        assignment[i] = minC;
+        changed = true;
+      }
+    }
+
+    if (!changed) break;
+
+    // Update centroids
+    const counts = new Array(k).fill(0);
+    for (let c = 0; c < centroids.length; c++) {
+      for (let d = 0; d < dim; d++) {
+        centroids[c][d] = 0;
+      }
+    }
+
+    for (let i = 0; i < n; i++) {
+      const c = assignment[i];
+      counts[c]++;
+      for (let d = 0; d < dim; d++) {
+        centroids[c][d] += points[i][d];
+      }
+    }
+
+    for (let c = 0; c < centroids.length; c++) {
+      if (counts[c] > 0) {
+        for (let d = 0; d < dim; d++) {
+          centroids[c][d] /= counts[c];
+        }
+      }
+    }
+  }
+
+  return assignment;
+}
