+    const chunkSize = Math.ceil(files.length / this.config.numWorkers);
+    const chunks = [];
+    for (let i = 0; i < files.length; i += chunkSize) {
+      chunks.push(files.slice(i, i + chunkSize));
+    }
+
+    const results = await Promise.all(chunks.map(chunk =>
